    context = raw[context_start:context_end]
    # decide
    ct = None
    # check hadith cues
    hadith_found = any(cue in context for cue in hadith_cues)
    ayah_found = any(cue in context for cue in ayah_cues)
    # if both keep based on heuristics: presence of 'قال النبي' strongly hadith else Aya
    if hadith_found and not ayah_found:
        ct = 'Hadith'
