        ct = 'Aya'
    elif hadith_found and ayah_found:
        # choose hadith if contains 'قال النبي' substring, else sounds like Aya
        if 'قال النبي' in context or 'قال رسول الله' in context:
            ct = 'Hadith'
        else:
            ct = 'Aya'
    else:
        # fallback: use pattern of text; if it starts with 'يا أيها' might be Aya
        if text.strip().startswith('يَا أَيُّهَا') or 'اللَّهِ' in text or 'اللَّهُ' in text:
